const fs = require('fs').promises;

async function writeContent(path, data) {
  return fs.writeFile(path, data, 'utf8');
}

async function appendContent(path, data) {
  return fs.appendFile(path, data, 'utf8');
}

module.exports = { writeContent, appendContent };
